mapper.sql:
from aiw_backtest_result b
where 1 = 1

    and b.owner_user_biz_id = #{criteria.ownerUserBizId}


    and b.strategy_code = #{criteria.strategyCode}


    and b.strategy_version = #{criteria.strategyVersion}


    and b.status = #{criteria.status}

mapper.select:
select b.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
